contracts/SybilRegistry.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

import "./interfaces/ISomniaAgents.sol";
import "./interfaces/ISybilRegistry.sol";

/// @title  SybilRegistry
/// @notice Scores a wallet's "humanness" 0-100 from its on-chain activity, using
///         Somnia's deterministic JSON API agent.
///
///         Flow (single agent call):
///           1. requestAttestation(wallet) asks the JSON API agent to fetch the
///              wallet's `transactions_count` from the block-explorer REST API.
///           2. handleTxCount() receives the count and derives a transparent,
///              banded score on-chain. More activity => higher score.
///
///         The JSON API agent is the correct tool here: reading a structured
///         on-chain metric is a deterministic data-fetch, not a language task.
///         (The earlier Parse Website + LLM design could not look up wallet data
///         via web search — see the project history.)
///
///         Attestations are valid for 90 days and reusable across all LaunchPools
///         that read this registry.

contract SybilRegistry is ISybilRegistry {

    // ── Somnia platform ────────────────────────────────────────────────────
    IAgentRequester public constant PLATFORM =
        IAgentRequester(0x037Bb9C718F3f7fe5eCBDB0b600D607b52706776);

    // JSON API Request agent — fetchUint(url, selector, decimals)
    uint256 public constant JSON_API_AGENT_ID = 13174292974160097713;

    // ── Deposit ──────────────────────────────────────────────────────────────
    // JSON API cost = platform reserve (~0.03) + 0.03 STT per validator (~0.12 min).
    // The score uses TWO signals (tx count + balance), so two chained agent calls.
    // We send a buffer so neither call is rejected at the edge of the minimum;
    // excess is refunded.
    uint256 public constant JSON_DEPOSIT  = 17e16;  // 0.17 STT per call
    uint256 public constant TOTAL_DEPOSIT = 40e16;  // 0.40 STT sent by caller (2 calls)

    // ── Attestation TTL ────────────────────────────────────────────────────
    uint256 public constant ATTESTATION_TTL = 90 days;

    // Block-explorer REST API. The wallet address is appended to the base, e.g.
    //   https://api.testnet.somnia.exploreme.pro/accounts/0xABC...
    // which returns JSON like
    //   {"address":"0x..","balance":3962...,"txsCount":75,"internalTxsCount":90,...}
    // The JSON API agent reads the `txsCount` field (a plain integer).
    // This is the explorer that actually indexes chainId 50312 wallet activity
    // (shannon-explorer returns 0; socialscan's /api/v2 returns HTTP 500).
    string public constant EXPLORER_BASE = "https://api.testnet.somnia.exploreme.pro/accounts/";
    string public constant TXCOUNT_SELECTOR = "txsCount";
    string public constant BALANCE_SELECTOR = "balance"; // native balance in wei

    // ── Storage ────────────────────────────────────────────────────────────
    struct Attestation {
        uint8   score;      // 0-100; higher = more active + more capital = more likely human
        uint256 timestamp;
        uint256 expiresAt;
        bool    exists;
    }

    mapping(address => Attestation) public  attestations;
    mapping(uint256 => address)     private _pending;     // requestId → wallet
    mapping(address => uint256)     private _partialTx;   // wallet → txCount carried between the 2 calls

    // ── Events ─────────────────────────────────────────────────────────────
    event AttestationRequested(address indexed wallet, uint256 indexed requestId);
    event AttestationStored(address indexed wallet, uint8 score, uint256 txCount, uint256 balanceWei);
    event AttestationFailed(address indexed wallet, ResponseStatus status);
    /// @dev Self-diagnosing: emits the raw validator bytes on any callback failure.
    event AgentDebug(address indexed wallet, string step, uint8 status, uint256 numResponses, bytes firstResult);

    // ── Step 1: fetch transaction count ──────────────────────────────────────
    /// @notice Request a Sybil attestation. Caller must send >= TOTAL_DEPOSIT
    ///         (0.40 STT, covers two JSON API calls). Excess is refunded.
    function requestAttestation(address wallet) external payable {
        require(msg.value >= TOTAL_DEPOSIT, "SybilRegistry: insufficient deposit");
        require(wallet != address(0),       "SybilRegistry: zero address");

        uint256 requestId = PLATFORM.createRequest{value: JSON_DEPOSIT}(
            JSON_API_AGENT_ID,
            address(this),
            this.handleTxCount.selector,
            _fetchPayload(wallet, TXCOUNT_SELECTOR)
        );
        _pending[requestId] = wallet;

        emit AttestationRequested(wallet, requestId);

        // keep JSON_DEPOSIT for the second (balance) call; refund the rest
        if (msg.value > 2 * JSON_DEPOSIT) {
            payable(msg.sender).transfer(msg.value - 2 * JSON_DEPOSIT);
        }
    }

    // ── Step 1 callback: store tx count, fetch balance ──────────────────────
    function handleTxCount(
        uint256 requestId,
        Response[] memory responses,
        ResponseStatus status,
        Request memory
    ) external {
        require(msg.sender == address(PLATFORM), "SybilRegistry: only platform");
        address wallet = _pending[requestId];
        delete _pending[requestId];

        if (status != ResponseStatus.Success || responses.length == 0) {
            emit AgentDebug(wallet, "txCount", uint8(status), responses.length, responses.length > 0 ? responses[0].result : bytes(""));
            emit AttestationFailed(wallet, status);
            return;
        }

        _partialTx[wallet] = abi.decode(responses[0].result, (uint256));

        uint256 reqId2 = PLATFORM.createRequest{value: JSON_DEPOSIT}(
            JSON_API_AGENT_ID,
            address(this),
            this.handleBalance.selector,
            _fetchPayload(wallet, BALANCE_SELECTOR)
        );
        _pending[reqId2] = wallet;
    }

    // ── Step 2 callback: combine signals, store attestation ─────────────────
    function handleBalance(
        uint256 requestId,
        Response[] memory responses,
        ResponseStatus status,
        Request memory
    ) external {
        require(msg.sender == address(PLATFORM), "SybilRegistry: only platform");
        address wallet = _pending[requestId];
        delete _pending[requestId];

        uint256 txCount = _partialTx[wallet];
        delete _partialTx[wallet];

        if (status != ResponseStatus.Success || responses.length == 0) {
            emit AgentDebug(wallet, "balance", uint8(status), responses.length, responses.length > 0 ? responses[0].result : bytes(""));
            emit AttestationFailed(wallet, status);
            return;
        }

        uint256 balanceWei = abi.decode(responses[0].result, (uint256));
        uint8 score = _score(txCount, balanceWei / 1e18); // balance in whole STT

        attestations[wallet] = Attestation({
            score:     score,
            timestamp: block.timestamp,
            expiresAt: block.timestamp + ATTESTATION_TTL,
            exists:    true
        });

        emit AttestationStored(wallet, score, txCount, balanceWei);
    }

    /// @dev Weighted, transparent score. Activity (cheap to farm) is capped at 50;
    ///      real capital held (costly to fake at scale) adds up to 50 more. A bot
    ///      army would need both many transactions AND real STT in every wallet.
    function _score(uint256 txCount, uint256 balSTT) internal pure returns (uint8) {
        uint256 t = txCount == 0 ? 0 : txCount < 5 ? 15 : txCount < 20 ? 30 : txCount < 100 ? 40 : 50;
        uint256 b = balSTT  == 0 ? 0 : balSTT  < 5 ? 20 : balSTT  < 20 ? 35 : balSTT  < 100 ? 45 : 50;
        uint256 s = t + b;
        return uint8(s > 100 ? 100 : s);
    }

    function _fetchPayload(address wallet, string memory selector) internal pure returns (bytes memory) {
        return abi.encodeWithSelector(
            IJsonApiAgent.fetchUint.selector,
            string.concat(EXPLORER_BASE, _addressToString(wallet)),
            selector,
            uint8(0)
        );
    }

    // ── ISybilRegistry ─────────────────────────────────────────────────────

    function isVerified(address wallet, uint8 minScore) external view returns (bool) {
        Attestation storage a = attestations[wallet];
        return a.exists && a.score >= minScore && block.timestamp <= a.expiresAt;
    }

    function getScore(address wallet) external view returns (uint8) {
        return attestations[wallet].score;
    }

    function isExpired(address wallet) external view returns (bool) {
        Attestation storage a = attestations[wallet];
        return !a.exists || block.timestamp > a.expiresAt;
    }

    // ── Internal helpers ───────────────────────────────────────────────────

    /// @dev Converts an address to its lowercase "0x..." hex string.
    function _addressToString(address addr) internal pure returns (string memory) {
        bytes memory data    = abi.encodePacked(addr);
        bytes memory hexChars = "0123456789abcdef";
        bytes memory result  = new bytes(42);
        result[0] = "0";
        result[1] = "x";
        for (uint256 i = 0; i < 20; i++) {
            result[2 + i * 2] = hexChars[uint8(data[i] >> 4)];
            result[3 + i * 2] = hexChars[uint8(data[i] & 0x0f)];
        }
        return string(result);
    }

    /// @dev Accept STT transfers.
    receive() external payable {}
}

contracts/TrustOracle.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

import "./interfaces/ISomniaAgents.sol";

/// @title  TrustOracle
/// @notice Autonomous, AI-derived "project trust score" (0-100) for launchpad
///         projects — the buyer-side counterpart to the SybilRegistry.
///
///         A project is registered with a name + domain. Somnia's Parse Website
///         agent searches the domain and the LLM agent rates the project's
///         legitimacy 0-100. The keeper agent discovers registered-but-unscored
///         projects and triggers scoring with no human input, so buyers see a
///         trust signal on every launch card.
contract TrustOracle {
    // ── Somnia platform ────────────────────────────────────────────────────
    IAgentRequester public constant PLATFORM =
        IAgentRequester(0x037Bb9C718F3f7fe5eCBDB0b600D607b52706776);
    uint256 public constant PARSE_WEBSITE_AGENT_ID = 12875401142070969085;
    uint256 public constant LLM_AGENT_ID            = 12847293847561029384;
    uint256 public constant PARSE_DEPOSIT = 40e16; // 0.40 STT
    uint256 public constant LLM_DEPOSIT   = 40e16; // 0.40 STT
    uint256 public constant TOTAL_DEPOSIT = 80e16; // 0.80 STT

    enum TrustStatus { NONE, REGISTERED, SCORING, SCORED, FAILED }

    struct Project {
        string  name;
        string  domain;
        uint8   score;       // 0-100
        TrustStatus status;
        uint256 updatedAt;
    }

    mapping(uint256 => Project)  public projects;        // poolId → project
    mapping(uint256 => uint256)  private _pending;       // agent requestId → poolId

    event ProjectRegistered(uint256 indexed poolId, string name, string domain);
    event TrustRequested(uint256 indexed poolId, uint256 requestId);
    event TrustScored(uint256 indexed poolId, uint8 score);
    event TrustFailed(uint256 indexed poolId);
    event AgentDebug(uint256 indexed poolId, string step, uint8 status, bytes firstResult);

    /// @notice Register a project's metadata so it can be scored.
    function registerProject(uint256 poolId, string calldata name, string calldata domain) external {
        require(bytes(domain).length > 0, "TrustOracle: empty domain");
        Project storage p = projects[poolId];
        require(p.status == TrustStatus.NONE, "TrustOracle: already registered");
        p.name = name;
        p.domain = domain;
        p.status = TrustStatus.REGISTERED;
        p.updatedAt = block.timestamp;
        emit ProjectRegistered(poolId, name, domain);
    }

    /// @notice Trigger AI scoring of a registered project. Send >= 0.80 STT.
    ///         Idempotent-friendly: callable when REGISTERED or after FAILED.
    function requestTrustScore(uint256 poolId) external payable {
        Project storage p = projects[poolId];
        // Re-scorable any time except while a request is already in flight.
        require(p.status != TrustStatus.NONE && p.status != TrustStatus.SCORING, "TrustOracle: not scorable");
        require(msg.value >= TOTAL_DEPOSIT, "TrustOracle: insufficient deposit");

        p.status = TrustStatus.SCORING;

        string[] memory noOptions = new string[](0);
        bytes memory payload = abi.encodeWithSelector(
            IParseWebsiteAgent.ExtractString.selector,
            "project_legitimacy",
            "What this website/project is, and any signals of legitimacy: product, docs, team, audits, activity, community",
            noOptions,
            // Generic so the agent always extracts the site's actual content; the LLM
            // then judges legitimacy from it. (Querying for a specific name the site
            // doesn't contain makes the agent return nothing and fail.)
            "Summarise what this website is about and any evidence that it represents a real, active, legitimate crypto project.",
            p.domain,
            true,      // resolveUrl = true (domain search)
            uint8(3),
            uint8(0)   // accept whatever is found — don't fail on a confidence threshold
        );
        // Single validator (threshold 1): a legitimacy summary is free-form text, so a
        // 3-validator majority can't agree on identical strings. For this advisory score
        // we take one agent's result. (Sybil + milestone verification keep full consensus.)
        uint256 requestId = PLATFORM.createAdvancedRequest{value: PARSE_DEPOSIT}(
            PARSE_WEBSITE_AGENT_ID, address(this), this.handleEvidence.selector, payload,
            1, 1, ConsensusType.Majority, 300
        );
        _pending[requestId] = poolId;

        emit TrustRequested(poolId, requestId);
        if (msg.value > TOTAL_DEPOSIT) payable(msg.sender).transfer(msg.value - TOTAL_DEPOSIT);
    }

    function handleEvidence(uint256 requestId, Response[] memory responses, ResponseStatus status, Request memory) external {
        require(msg.sender == address(PLATFORM), "TrustOracle: only platform");
        uint256 poolId = _pending[requestId];
        delete _pending[requestId];
        Project storage p = projects[poolId];

        if (status != ResponseStatus.Success || responses.length == 0) {
            p.status = TrustStatus.FAILED;
            emit AgentDebug(poolId, "parse", uint8(status), responses.length > 0 ? responses[0].result : bytes(""));
            emit TrustFailed(poolId);
            return;
        }

        string memory evidence = abi.decode(responses[0].result, (string));
        string memory prompt = string.concat(
            "Rate the legitimacy of the crypto project '", p.name, "' from 0 to 100, ",
            "where 100 = clearly legitimate with real product/docs/team and 0 = scam or no evidence.\n\n",
            "Evidence from ", p.domain, ":\n", evidence, "\n\n",
            "Return only a single integer 0-100."
        );
        bytes memory llmPayload = abi.encodeWithSelector(
            ILLMAgent.inferNumber.selector,
            prompt,
            "You are a careful crypto due-diligence analyst. Return only a number 0-100.",
            int256(0), int256(100), false
        );
        uint256 llmRequestId = PLATFORM.createAdvancedRequest{value: LLM_DEPOSIT}(
            LLM_AGENT_ID, address(this), this.handleScore.selector, llmPayload,
            1, 1, ConsensusType.Majority, 300
        );
        _pending[llmRequestId] = poolId;
    }

    function handleScore(uint256 requestId, Response[] memory responses, ResponseStatus status, Request memory) external {
        require(msg.sender == address(PLATFORM), "TrustOracle: only platform");
        uint256 poolId = _pending[requestId];
        delete _pending[requestId];
        Project storage p = projects[poolId];

        if (status != ResponseStatus.Success || responses.length == 0) {
            p.status = TrustStatus.FAILED;
            emit AgentDebug(poolId, "llm", uint8(status), responses.length > 0 ? responses[0].result : bytes(""));
            emit TrustFailed(poolId);
            return;
        }

        int256 raw = abi.decode(responses[0].result, (int256));
        uint8 score = uint8(uint256(raw > 100 ? int256(100) : raw < 0 ? int256(0) : raw));
        p.score = score;
        p.status = TrustStatus.SCORED;
        p.updatedAt = block.timestamp;
        emit TrustScored(poolId, score);
    }

    // ── Views ────────────────────────────────────────────────────────────────
    function getProject(uint256 poolId) external view returns (Project memory) {
        return projects[poolId];
    }

    receive() external payable {}
}

contracts/VestingVault.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "@openzeppelin/contracts/token/ERC20/utils/SafeERC20.sol";
import "./interfaces/ISomniaAgents.sol";
import "./interfaces/IVestingVault.sol";

/// @title  VestingVault
/// @notice Milestone-gated token vesting backed by on-chain consensus AI.
///
///         A project creates a schedule locking all team/investor tokens.
///         Each tranche unlocks only when an AI agent pipeline verifies that
///         the corresponding real-world milestone was genuinely completed:
///
///         Step 1 — LLM Parse Website scrapes the project's evidence URL
///                  (GitHub README, analytics page, audit report, etc.)
///         Step 2 — LLM Inference reads the scraped content and decides
///                  PASS or FAIL against the milestone description.
///
///         Multiple milestones can be in VERIFYING state simultaneously.

contract VestingVault is IVestingVault {
    using SafeERC20 for IERC20;

    // ── Somnia platform ────────────────────────────────────────────────────
    IAgentRequester public constant PLATFORM =
        IAgentRequester(0x037Bb9C718F3f7fe5eCBDB0b600D607b52706776);

    uint256 public constant PARSE_WEBSITE_AGENT_ID = 12875401142070969085;
    uint256 public constant LLM_AGENT_ID            = 12847293847561029384;

    // ── Deposits ───────────────────────────────────────────────────────────
    // Somnia agent cost = platform reserve (~0.03) + 0.10 STT per validator.
    // Default subcommittee is 3 → minimum 0.33 STT/step. We add a buffer so a
    // request is never rejected at the edge of the minimum.
    uint256 public constant PARSE_DEPOSIT  = 40e16;  // 0.40 STT (min 0.33 + buffer)
    uint256 public constant LLM_DEPOSIT    = 40e16;  // 0.40 STT (min 0.33 + buffer)
    uint256 public constant TOTAL_DEPOSIT  = 80e16;  // 0.80 STT sent by caller

    // ── Types ──────────────────────────────────────────────────────────────
    enum MilestoneStatus { PENDING, VERIFYING, PASSED, FAILED }

    struct Milestone {
        string          description;  // natural language requirement
        string          evidenceUrl;  // URL agents will scrape
        uint256         unlockAmount; // tokens released on PASS
        uint256         deadline;     // unix timestamp — must claim before this
        MilestoneStatus status;
    }

    struct VestingSchedule {
        address beneficiary;
        address token;
        uint256 totalAmount;
        uint256 unlockedAmount;
    }

    struct MilestoneInput {
        string  description;
        string  evidenceUrl;
        uint256 unlockAmount;
        uint256 deadline;
    }

    struct PendingVerification {
        uint256 scheduleId;
        uint256 milestoneIndex;
    }

    // ── Storage ────────────────────────────────────────────────────────────
    mapping(uint256 => VestingSchedule) public  schedules;
    mapping(uint256 => Milestone[])     public  milestones;  // scheduleId → milestones
    mapping(uint256 => PendingVerification) private _pending; // requestId → context
    uint256 public nextScheduleId;

    // ── Events ─────────────────────────────────────────────────────────────
    event ScheduleCreated(
        uint256 indexed scheduleId,
        address indexed beneficiary,
        address indexed token,
        uint256 totalAmount,
        uint256 milestoneCount
    );
    event MilestoneClaimed(
        uint256 indexed scheduleId,
        uint256 indexed milestoneIndex,
        uint256 indexed parseRequestId
    );
    event EvidenceCollected(
        uint256 indexed scheduleId,
        uint256 indexed milestoneIndex,
        uint256 indexed llmRequestId
    );
    event MilestonePassed(
        uint256 indexed scheduleId,
        uint256 indexed milestoneIndex,
        uint256 unlockedAmount
    );
    event MilestoneFailed(
        uint256 indexed scheduleId,
        uint256 indexed milestoneIndex
    );
    event TokensUnlocked(address indexed beneficiary, address indexed token, uint256 amount);
    /// @dev Emitted on any agent-callback failure with the raw validator response
    ///      bytes the platform handed us — makes failures self-diagnosing on-chain.
    event AgentDebug(
        uint256 indexed scheduleId,
        uint256 indexed milestoneIndex,
        string  step,        // "parse" or "verdict"
        uint8   status,      // ResponseStatus
        uint256 numResponses,
        bytes   firstResult
    );
    event MilestoneReset(uint256 indexed scheduleId, uint256 indexed milestoneIndex);
    event EmergencyWithdrawal(uint256 indexed scheduleId, address indexed beneficiary, uint256 amount);

    // ── Create schedule ────────────────────────────────────────────────────

    /// @notice Lock tokens in the vault with a set of milestone conditions.
    ///         Caller must have approved this contract to transfer `totalAmount` tokens.
    ///         The sum of all milestone unlockAmounts must equal totalAmount.
    function createSchedule(
        address           token,
        uint256           totalAmount,
        address           beneficiary,
        MilestoneInput[] calldata milestoneInputs
    ) external returns (uint256 scheduleId) {
        require(token != address(0),       "VestingVault: zero token");
        require(totalAmount > 0,           "VestingVault: zero amount");
        require(beneficiary != address(0), "VestingVault: zero beneficiary");
        require(milestoneInputs.length > 0, "VestingVault: no milestones");

        // Validate milestone amounts sum to totalAmount
        uint256 sum;
        for (uint256 i = 0; i < milestoneInputs.length; i++) {
            require(milestoneInputs[i].unlockAmount > 0, "VestingVault: zero unlock");
            require(milestoneInputs[i].deadline > block.timestamp, "VestingVault: past deadline");
            sum += milestoneInputs[i].unlockAmount;
        }
        require(sum == totalAmount, "VestingVault: amounts must sum to total");

        scheduleId = nextScheduleId++;

        schedules[scheduleId] = VestingSchedule({
            beneficiary:    beneficiary,
            token:          token,
            totalAmount:    totalAmount,
            unlockedAmount: 0
        });

        for (uint256 i = 0; i < milestoneInputs.length; i++) {
            milestones[scheduleId].push(Milestone({
                description:  milestoneInputs[i].description,
                evidenceUrl:  milestoneInputs[i].evidenceUrl,
                unlockAmount: milestoneInputs[i].unlockAmount,
                deadline:     milestoneInputs[i].deadline,
                status:       MilestoneStatus.PENDING
            }));
        }

        IERC20(token).safeTransferFrom(msg.sender, address(this), totalAmount);

        emit ScheduleCreated(scheduleId, beneficiary, token, totalAmount, milestoneInputs.length);
    }

    // ── Claim milestone: Step 1 ────────────────────────────────────────────

    /// @notice Trigger AI verification for a PENDING milestone.
    ///         Only callable by the schedule beneficiary.
    ///         Caller must send >= TOTAL_DEPOSIT (0.60 STT). Excess is refunded.
    function claimMilestone(
        uint256 scheduleId,
        uint256 milestoneIndex
    ) external payable {
        VestingSchedule storage schedule = schedules[scheduleId];
        require(msg.sender == schedule.beneficiary, "VestingVault: not beneficiary");
        require(milestoneIndex < milestones[scheduleId].length, "VestingVault: bad index");
        require(msg.value >= TOTAL_DEPOSIT, "VestingVault: insufficient deposit");

        Milestone storage m = milestones[scheduleId][milestoneIndex];
        require(m.status == MilestoneStatus.PENDING,      "VestingVault: not pending");
        require(block.timestamp <= m.deadline,            "VestingVault: deadline passed");

        m.status = MilestoneStatus.VERIFYING;

        string[] memory noOptions = new string[](0);

        // The Parse Website agent only works in domain-SEARCH mode (resolveUrl=true):
        //   - evidenceUrl is treated as a DOMAIN (e.g. "github.com", a project site)
        //   - the `prompt` is used as the natural-language SEARCH QUERY
        //   - direct-scrape mode (resolveUrl=false) does not work in the validator sandbox
        bytes memory payload = abi.encodeWithSelector(
            IParseWebsiteAgent.ExtractString.selector,
            "milestone_evidence",
            "Evidence that the milestone was completed: metrics, counts, dates, announcements, audit results",
            noOptions,
            string.concat(
                "Find evidence on this site that the following project milestone was completed: '",
                m.description,
                "'. Summarise any dates, counts, names, or announcements that confirm or refute it."
            ),
            m.evidenceUrl,
            true,     // resolveUrl = true — domain search (the only mode that works)
            uint8(3), // search up to 3 pages
            uint8(40) // confidence threshold
        );

        uint256 requestId = PLATFORM.createRequest{value: PARSE_DEPOSIT}(
            PARSE_WEBSITE_AGENT_ID,
            address(this),
            this.handleEvidenceResponse.selector,
            payload
        );

        _pending[requestId] = PendingVerification({
            scheduleId:     scheduleId,
            milestoneIndex: milestoneIndex
        });

        emit MilestoneClaimed(scheduleId, milestoneIndex, requestId);

        // Refund excess beyond what both agent calls will need
        uint256 totalNeeded = PARSE_DEPOSIT + LLM_DEPOSIT;
        if (msg.value > totalNeeded) {
            payable(msg.sender).transfer(msg.value - totalNeeded);
        }
    }

    // ── Step 1 Callback: fire LLM with scraped evidence ───────────────────
    function handleEvidenceResponse(
        uint256 requestId,
        Response[] memory responses,
        ResponseStatus status,
        Request memory
    ) external {
        require(msg.sender == address(PLATFORM), "VestingVault: only platform");

        PendingVerification memory pv = _pending[requestId];
        delete _pending[requestId];

        uint256 scheduleId     = pv.scheduleId;
        uint256 milestoneIndex = pv.milestoneIndex;
        Milestone storage m    = milestones[scheduleId][milestoneIndex];

        if (status != ResponseStatus.Success || responses.length == 0) {
            m.status = MilestoneStatus.FAILED;
            emit AgentDebug(scheduleId, milestoneIndex, "parse", uint8(status),
                responses.length, responses.length > 0 ? responses[0].result : bytes(""));
            emit MilestoneFailed(scheduleId, milestoneIndex);
            return;
        }

        string memory scrapedContent = abi.decode(responses[0].result, (string));

        string[] memory allowedValues = new string[](2);
        allowedValues[0] = "PASS";
        allowedValues[1] = "FAIL";

        string memory prompt = string.concat(
            "You are verifying whether a blockchain project milestone has been completed.\n\n"
            "Milestone requirement: \"", m.description, "\"\n\n"
            "Evidence scraped from ", m.evidenceUrl, ":\n",
            scrapedContent,
            "\n\n"
            "Rules:\n"
            "- Require clear, specific, quantitative evidence\n"
            "- Reject vague claims, unverifiable assertions, or missing data\n"
            "- Watch for metric gaming (e.g. fake users, wash transactions)\n"
            "- If evidence is ambiguous or insufficient, reply FAIL\n\n"
            "Reply with exactly one word: PASS or FAIL"
        );

        bytes memory llmPayload = abi.encodeWithSelector(
            ILLMAgent.inferString.selector,
            prompt,
            "You are a strict, impartial milestone verifier for a token launchpad. Your role is to protect investors by preventing teams from gaming their vesting schedule.",
            false,        // chainOfThought
            allowedValues
        );

        uint256 llmRequestId = PLATFORM.createRequest{value: LLM_DEPOSIT}(
            LLM_AGENT_ID,
            address(this),
            this.handleVerdictResponse.selector,
            llmPayload
        );

        _pending[llmRequestId] = PendingVerification({
            scheduleId:     scheduleId,
            milestoneIndex: milestoneIndex
        });

        emit EvidenceCollected(scheduleId, milestoneIndex, llmRequestId);
    }

    // ── Step 2 Callback: resolve milestone ────────────────────────────────
    function handleVerdictResponse(
        uint256 requestId,
        Response[] memory responses,
        ResponseStatus status,
        Request memory
    ) external {
        require(msg.sender == address(PLATFORM), "VestingVault: only platform");

        PendingVerification memory pv = _pending[requestId];
        delete _pending[requestId];

        uint256 scheduleId     = pv.scheduleId;
        uint256 milestoneIndex = pv.milestoneIndex;
        Milestone storage m    = milestones[scheduleId][milestoneIndex];
        VestingSchedule storage s = schedules[scheduleId];

        if (status != ResponseStatus.Success || responses.length == 0) {
            m.status = MilestoneStatus.FAILED;
            emit AgentDebug(scheduleId, milestoneIndex, "verdict", uint8(status),
                responses.length, responses.length > 0 ? responses[0].result : bytes(""));
            emit MilestoneFailed(scheduleId, milestoneIndex);
            return;
        }

        string memory verdict = abi.decode(responses[0].result, (string));
        bool passed = keccak256(bytes(verdict)) == keccak256(bytes("PASS"));

        if (passed) {
            m.status = MilestoneStatus.PASSED;
            s.unlockedAmount += m.unlockAmount;

            IERC20(s.token).safeTransfer(s.beneficiary, m.unlockAmount);

            emit MilestonePassed(scheduleId, milestoneIndex, m.unlockAmount);
            emit TokensUnlocked(s.beneficiary, s.token, m.unlockAmount);
        } else {
            m.status = MilestoneStatus.FAILED;
            emit MilestoneFailed(scheduleId, milestoneIndex);
        }
    }

    // ── Milestone recovery ─────────────────────────────────────────────────

    /// @notice Reset a FAILED milestone back to PENDING so it can be retried.
    ///         Only the beneficiary may call this — they already bear the cost
    ///         of re-paying the 0.60 STT agent fee on the next claimMilestone call.
    ///         Intended for cases where the AI platform had a transient failure
    ///         that incorrectly marked a completed milestone as FAILED.
    function resetMilestone(uint256 scheduleId, uint256 milestoneIndex) external {
        VestingSchedule storage schedule = schedules[scheduleId];
        require(msg.sender == schedule.beneficiary,            "VestingVault: not beneficiary");
        require(milestoneIndex < milestones[scheduleId].length, "VestingVault: bad index");

        Milestone storage m = milestones[scheduleId][milestoneIndex];
        require(m.status == MilestoneStatus.FAILED, "VestingVault: only FAILED milestones can be reset");
        require(block.timestamp <= m.deadline,      "VestingVault: deadline passed");

        m.status = MilestoneStatus.PENDING;

        emit MilestoneReset(scheduleId, milestoneIndex);
    }

    /// @notice Emergency withdrawal of all remaining locked tokens.
    ///         Only callable by the beneficiary, and only after ALL milestones
    ///         have passed their deadline (i.e. there is no legitimate path left
    ///         to unlock them via the AI pipeline).
    ///         Releases only the portion that was never unlocked.
    function emergencyWithdraw(uint256 scheduleId) external {
        VestingSchedule storage schedule = schedules[scheduleId];
        require(msg.sender == schedule.beneficiary, "VestingVault: not beneficiary");

        Milestone[] storage ms = milestones[scheduleId];

        // All milestones must be either past their deadline or already resolved
        // (PASSED/FAILED), with none still PENDING or VERIFYING.
        for (uint256 i = 0; i < ms.length; i++) {
            MilestoneStatus s = ms[i].status;
            if (s == MilestoneStatus.PENDING || s == MilestoneStatus.VERIFYING) {
                require(
                    block.timestamp > ms[i].deadline,
                    "VestingVault: active milestone exists - use claimMilestone first"
                );
            }
        }

        uint256 remaining = schedule.totalAmount - schedule.unlockedAmount;
        require(remaining > 0, "VestingVault: nothing to withdraw");

        schedule.unlockedAmount = schedule.totalAmount; // mark all as consumed

        IERC20(schedule.token).safeTransfer(schedule.beneficiary, remaining);

        emit EmergencyWithdrawal(scheduleId, schedule.beneficiary, remaining);
    }

    // ── IVestingVault ──────────────────────────────────────────────────────

    function getUnlocked(uint256 scheduleId) external view returns (uint256) {
        return schedules[scheduleId].unlockedAmount;
    }

    function getMilestoneCount(uint256 scheduleId) external view returns (uint256) {
        return milestones[scheduleId].length;
    }

    // ── View helpers ───────────────────────────────────────────────────────

    function getMilestones(uint256 scheduleId) external view returns (Milestone[] memory) {
        return milestones[scheduleId];
    }

    function getMilestone(
        uint256 scheduleId,
        uint256 milestoneIndex
    ) external view returns (Milestone memory) {
        return milestones[scheduleId][milestoneIndex];
    }

    /// @dev Accept STT to hold the step-2 reserve between callbacks
    receive() external payable {}
}
